workspace.tests/promiseUtils.test.mjs:
import { runAll } from '../src/promiseUtils.mjs';

const assert = (c, m) => { if (!c) throw new Error(m); };

function delay(ms, value) {
  return new Promise(resolve => setTimeout(() => resolve(value), ms));
}

async function runTests() {
  // Test 1: all promises resolve within timeout
  const r1 = await runAll([
    delay(10, 'a'),
    delay(20, 'b'),
    delay(30, 'c')
  ], 500);
  assert(JSON.stringify(r1) === JSON.stringify(['a', 'b', 'c']), 'Should resolve all values but got ' + JSON.stringify(r1));

  // Test 2: timeout triggers rejection
  try {
    await runAll([
      delay(10, 'fast'),
      delay(5000, 'slow')
    ], 50);
    assert(false, 'Should have thrown a timeout error');
  } catch (e) {
    assert(e.message.toLowerCase().includes('timeout'), 'Error should mention timeout but got: ' + e.message);
  }

  // Test 3: no timeout (undefined) works like normal Promise.all
  const r3 = await runAll([
    delay(10, 1),
    delay(20, 2)
  ]);
  assert(JSON.stringify(r3) === JSON.stringify([1, 2]), 'Without timeout should work like Promise.all but got ' + JSON.stringify(r3));

  // Test 4: empty array resolves immediately
  const r4 = await runAll([], 100);
  assert(JSON.stringify(r4) === JSON.stringify([]), 'Empty array should resolve to [] but got ' + JSON.stringify(r4));

  // Test 5: timeout of 0 should still reject for async promises
  try {
    await runAll([delay(50, 'x')], 0);
    assert(false, 'Should have thrown for timeout of 0');
  } catch (e) {
    assert(e.message.toLowerCase().includes('timeout'), 'Error should mention timeout but got: ' + e.message);
  }

  console.log('ALL TESTS PASSED');
}

runTests();
